4/original.png?1772582712","https://braze-images.com/appboy/communication/assets/image_assets/images/69a0278848af5f006481b275/original.png?1772103559","https://braze-images.com/appboy/communication/assets/image_assets/images/69a02781c3ae69006330582b/original.png?1772103553"],"message":"<!DOCTYPE html>
<html lang="ko-KR">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1, viewport-fit=cover">
  <link href="https://assets.cdn.soomgo.com/braze-iam/style/typography.css" rel="stylesheet">
  <link href="https://assets.cdn.soomgo.com/braze-iam/style/modal.css" rel="stylesheet">
  <link href="https://assets.cdn.soomgo.com/braze-iam/style/button.css" rel="stylesheet">
  <style>
    @import url('https://cdn.jsdelivr.net/gh/orioncactus/pretendard@v1.3.9/dist/web/variable/pretendardvariable-dynamic-subset.min.css');
    *{margin:0;padding:0;box-sizing:border-box;-webkit-user-select:none;user-select:none}
    html,body{width:100%;height:100%;background:transparent;font-family:'Pretendard Variable',Pretendard,'Noto Sans KR',-apple-system,sans-serif;overflow:hidden}

    .braze-modal{position:fixed;inset:0;display:flex;align-items:center;justify-content:center;z-index:9999}
    .background{position:fixed;inset:0;background:rgba(0,0,0,.65);z-index:1}

    /* ── Modal container ── */
    .chess-modal{
      position:relative;z-index:2;
      width:295px;height:295px;
      background:#1C242F;
      border-radius:12px;overflow:hidden;
      box-shadow:0 24px 80px rgba(0,0,0,0.5);
    }

    /* ── Chess background ── */
    .chess-bg{
      position:absolute;inset:0;
      background-image:url("https://braze-images.com/appboy/communication/assets/image_assets/images/69a777395a64dd0063bdd544/original.png?1772582712");
      background-size:cover;background-position:center;
      z-index:0;
    }

    /* ── Purple glow (하단 빛) ── */
    .purple-glow{
      position:absolute;
      width:100%;height:220px;
      left:0;bottom:-30px;
      z-index:1;pointer-events:none;
      background:radial-gradient(ellipse 80% 60% at 50% 100%,rgba(105,59,242,0.45) 0%,rgba(105,59,242,0.15) 40%,transparent 70%);
      filter:blur(20px);
    }
    .purple-glow-rim{
      position:absolute;
      width:100%;height:130px;
      left:0;bottom:0;
      z-index:2;pointer-events:none;
      background:radial-gradient(ellipse 70% 50% at 50% 100%,rgba(241,238,255,0.12) 0%,transparent 60%);
      filter:blur(10px);
    }

    /* ── Noise overlay ── */
    .noise{
      position:absolute;inset:0;
      mix-blend-mode:overlay;opacity:0.5;z-index:18;
      pointer-events:none;
      background-image:url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)'/%3E%3C/svg%3E");
      background-size:128px 128px;
    }

    /* ── Close button ── */
    .close-button{
      position:absolute;top:8px;right:8px;z-index:30;
      padding:4px;border:none;background:none;cursor:pointer;
    }

    /* ── Text ── */
    .chess-text{
      position:absolute;left:0;right:0;top:18px;
      display:flex;flex-direction:column;align-items:center;
      z-index:20;pointer-events:none;
    }
    .chess-text .subtitle{
      font-weight:600;font-size:13px;line-height:20px;
      text-align:center;letter-spacing:-0.02em;color:#C5B6FF;
      margin-top:4px;
    }
    .chess-text .title{
      font-weight:800;font-size:26px;line-height:34px;
      text-align:center;letter-spacing:-1px;color:#FFFFFF;
      margin-top:0;
    }

    /* ── Knight with shimmer ── */
    .knight-wrap{
      position:absolute;
      width:60px;height:109px;
      left:calc(50% - 30px);top:118px;
      z-index:10;
    }
    .knight-wrap img{
      position:absolute;inset:0;
      width:100%;height:100%;object-fit:contain;
      filter:drop-shadow(0 4px 16px rgba(0,0,0,0.5));
    }
    .knight-wrap .outline{
      animation:shimmerOutline 1.4s ease-in-out infinite;
    }
    .knight-wrap .real{
      animation:shimmerReal 1.4s ease-in-out infinite;
    }
    @keyframes shimmerOutline{0%,100%{opacity:0.8}50%{opacity:0}}
    @keyframes shimmerReal{0%,100%{opacity:0}50%{opacity:0.8}}

    /* ── Knight shadow ── */
    .knight-shadow{
      position:absolute;width:55px;height:14px;
      left:calc(50% - 27px);top:231px;
      background:linear-gradient(90deg,rgba(0,0,0,0) -50%,#000 170%);
      filter:blur(4px);z-index:8;opacity:0.6;
    }

    /* ── CTA ── */
    .chess-cta{
      position:absolute;left:0;right:0;bottom:0;
      padding:0 16px 16px;z-index:25;
    }
    .chess-cta a{
      display:flex;justify-content:center;align-items:center;
      width:100%;height:44px;
      background:#693BF2;border:none;border-radius:10px;
      cursor:pointer;transition:all 0.15s ease;text-decoration:none;
    }
    .chess-cta a:active{transform:scale(0.98);filter:brightness(0.95)}
    .chess-cta a span{
      font-family:'Pretendard Variable',Pretendard,sans-serif;
      font-weight:600;font-size:15px;line-height:20px;color:#FFF;
    }
  </style>
</head>
<body>
<!--
  앱 미설치 유저 안내 모달 (나이트 체스 테마)
  - 나이트 outline 깜빡임 (아직 소환 안 된 느낌)
  - CTA: 에어브릿지 딥링크로 앱 스토어 이동
-->
<div class="braze-modal">
  <div class="background"></div>
  <div class="chess-modal">

    <!-- Chess background -->
    <div class="chess-bg"></div>

    <!-- Purple glow -->
    <div class="purple-glow"></div>
    <div class="purple-glow-rim"></div>

    <!-- Close -->
    <button class="close-button" onclick="closeModal()" aria-label="닫기">
      <svg width="24" height="24" viewBox="0 0 24 24" fill="none"><path d="M18 6L6 18M6 6L18 18" stroke="rgba(255,255,255,0.5)" stroke-width="2" stroke-linecap="round"/></svg>
    </button>

    <!-- Text (이미지에 포함) -->

    <!-- Knight (outline shimmer + real) -->
    <div class="knight-shadow"></div>
    <div class="knight-wrap">
      <img class="outline" src="https://braze-images.com/appboy/communication/assets/image_assets/images/69a0278848af5f006481b275/original.png?1772103559" alt="">
      <img class="real" src="https://braze-images.com/appboy/communication/assets/image_assets/images/69a02781c3ae69006330582b/original.png?1772103553" alt="">
    </div>

    <!-- Noise overlay -->
    <div class="noise"></div>

    <!-- CTA -->
    <div class="chess-cta">
      <a href="https://airbridge.soomgo.com/checkmate" target="_blank" rel="noopener">
        <span>나이트 소환하기</span>
      </a>
    </div>

  </div>
</div>

<script>
function getBridge() { return window.brazeBridge || window.appboyBridge || null; }

function closeModal() {
  var b = getBridge();
  if (b && b.closeMessage) b.closeMessage();
}
